// power computes base^exp for exp >= 0 in O(log exp) multiplications.
func power(base, exp int) int {
	if exp == 0 {
		return 1
	}
	half := power(base, exp/2)
	if exp%2 == 0 {
		return half * half
	}
	return base * half * half
}

