// height returns the number of levels; an empty tree has height 0.
func height(n *node) int {
	if n == nil {
		return 0
	}
	l, r := height(n.left), height(n.right)
	if l > r {
		return l + 1
	}
	return r + 1
}

func main() {
	tree := &node{
		left:  &node{left: &node{}}, // depth 3 on the left
		right: &node{},
	}
	fmt.Println("height:", height(tree)) // 3
}
