// mergeSorted merges two ascending slices into one ascending slice in O(n+m).
func mergeSorted(a, b []int) []int {
	out := make([]int, 0, len(a)+len(b))
	i, j := 0, 0
	for i < len(a) && j < len(b) {
		if a[i] <= b[j] {
			out = append(out, a[i])
			i++
		} else {
			out = append(out, b[j])
			j++
		}
	}
	out = append(out, a[i:]...) // append whatever remains (one of these is empty)
	out = append(out, b[j:]...)
	return out
}

