		if i < len(runes) && runes[i] == runes[i-1] {
			count++
			continue
		}
		b.WriteRune(runes[i-1])
		b.WriteString(strconv.Itoa(count))
		count = 1
	}
	return b.String()
}

func main() {
	fmt.Println(rle("aaabbbcccd")) // a3b3c3d1
}
